CustomField.formula:
/*Returns yy,yn,ny,nn yy: Credit Block and Delivery Block yn: Credit Block only ny: Delivery Block Only nn: No Blocks */
/*If Credit status is Approved or blank, then it is Not Blocked by credit*/ IF(Credit_Status_Name__c ="Approved" || ISBLANK(Credit_Status_Name__c),"n","y")
& /*If delivery block on Summary is blank AND total blocked items is zero, then Not blocked by Delivery */ IF(ISBLANK(Delivery_Block__c) && fxBlockedItems__c =0 ,"n","y")
